        .form-group textarea {
            resize: vertical;
            min-height: 120px;
        }

        .btn-submit {
            width: 100%;
            cursor: pointer;
            font-size: 1rem;
            margin-top: 1rem;
            border: none;
            transition: all 0.3s ease;
        }

        .btn-submit:hover {
            transform: translateY(-3px);
            box-shadow: 0 15px 40px rgba(229, 231, 235, 0.4);
        }

        /* Footer */
        .footer {
            padding: 60px 2rem 40px;
            border-top: 1px solid var(--border-color);
            text-align: center;
            background: rgba(0, 0, 0, 0.5);
            margin-top: 80px;
        }

        .footer-content {
            max-width: 1400px;
            margin: 0 auto;
        }

        .footer-links {
            margin-bottom: 2rem;
            display: flex;
            justify-content: center;
            align-items: center;
            flex-wrap: wrap;
            gap: 0.5rem;
        }

        .footer-links a {
            color: var(--text-secondary);
            text-decoration: none;
            font-weight: 500;
            text-transform: uppercase;
            letter-spacing: 1px;
            font-size: 0.9rem;
            transition: all 0.3s ease;
            position: relative;
            padding: 0 0.5rem;
        }

        .footer-links a:hover {
            color: var(--primary-cyan);
            text-shadow: 0 0 10px var(--primary-cyan);
            transform: translateY(-2px);
        }

        .footer-links a::after {
            content: '';
            position: absolute;
            bottom: -3px;
            left: 50%;
            transform: translateX(-50%);
            width: 0;
            height: 1px;
            background: var(--primary-cyan);
            transition: width 0.3s ease;
            box-shadow: 0 0 5px var(--primary-cyan);
        }

        .footer-links a:hover::after {
            width: 80%;
        }

        .footer-separator {
            color: var(--primary-cyan);
            opacity: 0.5;
            font-size: 0.8rem;
            margin: 0 0.2rem;
        }

        .footer-bottom {
            color: var(--text-secondary);
            font-size: 0.9rem;
        }

        .footer-bottom p {
            margin: 0.5rem 0;
        }

        .footer-credit {
            font-size: 0.85rem;
            opacity: 0.8;
            margin-top: 0.5rem;
        }

        .footer-credit a {
            color: var(--primary-cyan);
            text-decoration: none;
            transition: all 0.3s ease;
            font-weight: 600;
        }

        .footer-credit a:hover {
            color: var(--primary-pink);
            text-shadow: 0 0 10px var(--primary-pink);
            text-decoration: underline;
        }

        /* Mobile Responsive */
        @media (max-width: 768px) {
            .mobile-menu-button {
                display: block !important;
            }

            .nav-links {
                display: none;
            }

            .nav-bottom .cyber-button {
                display: none;
            }

            .hero-title {
                font-size: 2.5rem;
            }

            .hero-buttons {
                flex-direction: column;
                align-items: center;
            }

            .btn-primary, .btn-secondary {
                width: 100%;
                max-width: 300px;
            }

            .features-grid {
                grid-template-columns: 1fr;
            }

            .pricing-grid {
                grid-template-columns: 1fr;
            }

            .pricing-card.featured {
                transform: none;
            }

            .stats-grid {
                grid-template-columns: repeat(2, 1fr);
            }

            .contact {
                padding: 80px 1rem;
            }

            .contact-form {
                padding: 2rem;
            }

            .footer-links {
                flex-direction: column;
                gap: 1rem;
            }

            .footer-links a {
                padding: 0.5rem 1rem;
            }

            .footer-separator {
                display: none;
            }

            .footer {
                margin-top: 40px;
                padding: 40px 1rem 30px;
            }
        }

        @media (max-width: 480px) {
            .mobile-menu {
                width: 90%;
                max-width: none;
            }

            .mobile-menu-header {
                padding: 1.5rem;
            }

            .mobile-menu-nav a {
                padding: 1.2rem 1.5rem;
                font-size: 1rem;
            }

            .mobile-menu-cta {
                padding: 1.5rem;
            }

            .cyber-button {
                padding: 0.8rem 1.5rem;
                font-size: 0.9rem;
            }

            .hero-title {
                font-size: 2rem;
            }

            .hero-nexus, .hero-flow {
                display: block;
                margin: 0;
            }
        }

        /* Scroll animations */
        .fade-up {
            opacity: 0;
            transform: translateY(50px);
            transition: all 0.8s ease;
        }

        .fade-up.visible {
            opacity: 1;
            transform: translateY(0);
        }

        /* Data streams */
        .data-streams {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            overflow: hidden;
            z-index: -3;
            pointer-events: none;
        }

        .data-stream {
            position: absolute;
            height: 1px;
            background: linear-gradient(90deg, transparent, var(--primary-cyan), transparent);
            opacity: 0;
            animation: dataFlow 3s ease-in-out infinite;
        }

        .data-stream:nth-child(odd) {
            background: linear-gradient(90deg, transparent, var(--primary-pink), transparent);
            animation-duration: 4s;
        }

        @keyframes dataFlow {
            0% {
                width: 0;
                opacity: 0;
                transform: translateX(0);
            }
            50% {
                width: 300px;
                opacity: 0.8;
            }
            100% {
                width: 0;
                opacity: 0;
                transform: translateX(100vw);
            }
        }

        /* Performance optimization for mobile */
        @media (max-width: 768px) {
            .matrix-rain {
                display: none;
            }

            .particles {
                opacity: 0.5;
            }

            .particle {
                animation-duration: 30s !important;
            }

            .orb {
                filter: blur(100px);
                opacity: 0.3;
            }

            .scanlines::before {
                animation: none;
                transform: translateY(0);
            }

            .data-streams {
                display: none;
            }

            .noise-overlay {
                display: none;
            }
        }

        /* Reduced motion for accessibility */
        @media (prefers-reduced-motion: reduce) {
            .cyber-gradient,
            .grid-lines,
            .grid-glow,
            .particle,
            .orb,
            .matrix-column,
            .scanlines::before,
            .data-stream {
                animation: none !important;
            }
        }

        /* Custom scrollbar */
        ::-webkit-scrollbar {
            width: 8px;
        }

        ::-webkit-scrollbar-track {
            background: var(--darker-bg);
        }

        ::-webkit-scrollbar-thumb {
            background: linear-gradient(var(--primary-cyan), var(--primary-pink));
            border-radius: 4px;
        }

        ::-webkit-scrollbar-thumb:hover {
            background: linear-gradient(var(--primary-pink), var(--primary-cyan));
        }
